import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class MythicalBlueprintOpenParser implements IMessageParser
{
private _sessionId = 0;
private _blueprintItemId = 0;

private _slotCount = 0;

private _weaponInvItemId = 0;
private _augmentInvItemId = 0;
private _optionalInvItemId = 0;

private _predictedUpgradeId = 0;
private _craftable = false;

public flush(): boolean
{
this._sessionId = 0;
this._blueprintItemId = 0;

this._slotCount = 0;

this._weaponInvItemId = 0;
this._augmentInvItemId = 0;
this._optionalInvItemId = 0;

this._predictedUpgradeId = 0;
this._craftable = false;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match MythicalBlueprintOpenComposer.java EXACTLY
this._sessionId = wrapper.readInt();
this._blueprintItemId = wrapper.readInt();

this._slotCount = wrapper.readInt();

this._weaponInvItemId = wrapper.readInt();
this._augmentInvItemId = wrapper.readInt();
this._optionalInvItemId = wrapper.readInt();

this._predictedUpgradeId = wrapper.readInt();
this._craftable = wrapper.readBoolean();

return true;
}

public get sessionId(): number { return this._sessionId; }
public get blueprintItemId(): number { return this._blueprintItemId; }

public get slotCount(): number { return this._slotCount; }

public get weaponInvItemId(): number { return this._weaponInvItemId; }
public get augmentInvItemId(): number { return this._augmentInvItemId; }
public get optionalInvItemId(): number { return this._optionalInvItemId; }

public get predictedUpgradeId(): number { return this._predictedUpgradeId; }
public get craftable(): boolean { return this._craftable; }
}
